+    private ProblemDetails CreateProblemDetails(ErrorContext errorContext, HttpContext httpContext)
+    {
+        var statusCode = httpContext.Response.StatusCode;
+        var reasonPhrase = WebUtilities.ReasonPhrases.GetReasonPhrase(statusCode);
+        var typeUri = _options.ExceptionTypeUriProvider?.Invoke(errorContext.Exception.GetType()) ?? "about:blank";
+        var problemDetails = new ProblemDetails
+        {
+            Type = typeUri,
+            Title = string.Equals(typeUri, "about:blank", StringComparison.OrdinalIgnoreCase)
+                ? (reasonPhrase ?? statusCode.ToString())
+                : TypeNameHelper.GetTypeDisplayName(errorContext.Exception.GetType()),
+            Detail = errorContext.Exception.Message,
+            Status = statusCode
+        };
